var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"……누구인가.","JPN":"……何者だ。","ENG":"...Who is it?","TWN":"……是誰？"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_BIG_02"},{"id":"L5_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"누가 악단이 만들어낸 흉측한 선박을 다시금 건드리는가.","JPN":"楽団が作り出した忌まわしい船舶に触れたのは、どこの者だ。","ENG":"Who dares touch the vile ship made by the Orchestra?","TWN":"是誰再次觸碰了樂團製造的醜陋艦船？"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"그 선박은 좌초되었으나, 여전히 역병의 악취가 가득한 상자와 같을지니.","JPN":"その船舶は座礁したが、今以て疫病の悪臭に満ちた箱。","ENG":"The ship has been stranded. Yet, it reeks like a chest full of the stench of the plague.","TWN":"那艘船雖然擱淺了，但仍像一個充滿瘟疫惡臭的箱子。"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"함부로 상자를 열어 버린 자 또한 필히 악한 의도를 가지고 있을 터.","JPN":"迂闊に箱を開けたというのなら、さぞ悪意を持っているのであろう。","ENG":"Anyone careless enough to open that chest is bound to have evil intentions.","TWN":"擅自打開之人必定也懷有惡意。"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그렇군요. 아무래도 당신은 절 기억하지 못하는 모양이네요.","JPN":"そうですか。どうやらあなたは私のことを覚えていないようですね。","ENG":"I see. It seems that you don't remember me.","TWN":"原來如此。看來你並不記得我了。"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"후훗…….","JPN":"ふふっ……","ENG":"Haha...","TWN":"呵呵……"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그럴 거라고 짐작은 하고 있었지만, 막상 예상이 맞아 떨어지니 참 섭섭하군요.","JPN":"予想はしていました。でも、いざ予想が当たると寂しいものですね。","ENG":"I was anticipating this, but I'm disappointed that my prediction turned out to be right.","TWN":"雖然我猜到了會這樣，但真的應驗了還是有點失落。"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"왜냐하면 그날 이후, 저는 단 한 순간도 당신을 잊은 적이 없으니까.","JPN":"なぜならあの日以来、私は一瞬たりともあなたを忘れたことがないのだから。","ENG":"Because since that day, I have never forgotten about you.","TWN":"從那天起，我可是從未忘記過你。"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"너는……?","JPN":"そなたは……？","ENG":"You are...?","TWN":"你是……？"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그래요.","JPN":"そうです。","ENG":"Very well.","TWN":"沒錯。"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L20_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그때는 알지 못했지만, 이제는 알고 있답니다.","JPN":"あの時はわかりませんでしたが、今はわかります。","ENG":"I didn't know then, but I know now.","TWN":"那時候不知道，但現在我知道了。"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"이미 그림자로 몰락해 버린 당신을 움직이게 만드는 망집이 후회라는 것.","JPN":"すでにシャドウになり下がったあなたを動かす妄執は後悔だということ。","ENG":"That the obsession that drives you, an already fallen Shadow, is regret.","TWN":"已經墮入陰影的你，被一種名為後悔的妄念所驅動。"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"기계적으로 후회를 반복할 뿐, 당신은 아무런 대책 없이 수많은 세계를 방랑해 왔다는 것.","JPN":"機械的に後悔を繰り返すだけで、あなたはなんの策もなしに数多の世界を放浪してきたのだということ。","ENG":"You repeat your regrets while wandering countless worlds without any solution.","TWN":"機械地重複著這種感情，你在無數個世界中漫無目的地遊蕩。"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"당신에게 있어, 저의 세계는 그저 마왕을 막아내지 못한 무수한 실패들 중 하나였다는 것.","JPN":"あなたにとって私の世界は、魔王を止められなかった、無数の失敗の一つにすぎなかったということ。","ENG":"To you, my world is one of many failures that couldn't stop the Demon Lord.","TWN":"對你來說，我的世界只不過是無數未能阻止魔王的失敗了的其中之一。"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그리고…….","JPN":"そして……","ENG":"And...","TWN":"以及……"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"당신이 마왕 타기리온을 만들어낸 장본인이라는 것.","JPN":"あなたが、魔王タギリオンを生み出した張本人だということ。","ENG":"That you are you one who created the Demon Lord Thagirion.","TWN":"你就是創造出魔王塔基里昂的罪魁禍首。"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_MINISTRA_DAMAGE_DOWN"},{"id":"L29_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"나의 우행을 부정할 생각은 없을지니.","JPN":"我の愚行を否定するつもりはない。","ENG":"I will not deny my foolish deeds.","TWN":"我並不打算否認我的愚行。"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"그 끝에 다다른 것이 결국 부질없는 후회뿐일지라도.","JPN":"辿り着いたその先が、空虚な後悔だけであろうとも。","ENG":"Even if what awaits me at the end is nothing but regret.","TWN":"即使到頭來獲得的只是徒勞的後悔。"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"나는 속죄를 위해 싸우겠다.","JPN":"我は贖罪のために戦い続けよう。","ENG":"I will fight for atonement.","TWN":"我會為了贖罪而戰。"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"……보세요.","JPN":"……ほら。","ENG":"...Look.","TWN":"……看啊。"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"당신은 또 그런 태도를 보이죠.","JPN":"あなたはまたそんな態度を見せる。","ENG":"You're showing that attitude again.","TWN":"你又擺出那種態度了。"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"제가 뭘 숨기고 있는지 모르면서, 무슨 목적을 감추고 있는지도 모르면서…….","JPN":"私が何を隠しているのかも知らず、何の目的で動いているのかも知らずに……","ENG":"You don't know what I'm hiding, or my purpose...","TWN":"你不知道我在隱藏什麼，也不知道我有什麼目的……"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그저 홀로, 오로지 고독하게…….","JPN":"ただ一人、孤独に……","ENG":"You are alone... Isolated...","TWN":"只是獨自一人，孤獨地……"},"stage":{"bg":"BACKSTREET","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"누구에게도 이해받지 못하고, 누구의 도움도 바라지 않으며.","JPN":"誰にも理解されず、誰の助けも求めず……","ENG":"No one to understand you, and not wanting help from others.","TWN":"不渴求理解，也不乞求幫助。"},"stage":{"bg":"BACKSTREET","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"결과적으로는……. 혼자서는 감당조차 할 수 없는 문제를 끌어안은 주제에……!!","JPN":"その結果……一人では耐えきれない問題を抱えているくせに……！！","ENG":"As a result... you have taken upon yourself a problem that you can't handle on your own...!!","TWN":"結果卻是……抱著自己無法承受的問題……！！"},"stage":{"bg":"BACKSTREET","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"후회를 반복하지 않겠다며, 그저 입으로만 되뇌고 있을 뿐이니까……!","JPN":"後悔を繰り返さないと、口で言っているだけだから……！","ENG":"All you do is say that you will not repeat your regrets...!","TWN":"說什麼不再後悔，只不過是嘴上說說而已……!"},"stage":{"bg":"BACKSTREET","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"속죄라고요!?","JPN":"贖罪ですって！？","ENG":"Atonement?!","TWN":"贖罪嗎！?"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그래서? 당신의 그 속죄라는 말에 정말로 진정성이라는 게 존재하긴 하나요?","JPN":"それで？　あなたのその贖罪という言葉に、誠の心はあるのですか？","ENG":"So what? Does your atonement even have an ounce of sincerity?","TWN":"你所謂的贖罪，真的有誠意嗎？"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"당신이 조금 더 일찍 도착했더라면……! 조금 더 빨리 진실을 이야기했다면……!","JPN":"あなたがもう少し早く着いていれば……！　もっと早く真実を語っていれば……！","ENG":"If you had arrived a little earlier...! If you had said the truth a little sooner...!","TWN":"如果你能早點趕到……！如果你能早點說出真相……！"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"우리는 다른 결말을 맞이할 수도 있었어…….","JPN":"私たちは違う結末を向かえたかもしれないのに……","ENG":"Then we would have had a different ending.","TWN":"我們本可以迎來不同的結局……"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"내게 어떤 원한을 가지고 있는지, 이젠 알 수 없으나.","JPN":"我に何の恨みを持っているか、わかるすべはないが……","ENG":"I do not know what grudge you hold anymore.","TWN":"雖然我現在還不知道你對我有什麼怨恨。"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"이 또한 피할 수 없는 내 우행의 결과일 터. 변명은 하지 않겠다. 그러니…….","JPN":"これもまた避けられぬ我の愚行の結果。言い訳はせぬ。だから……","ENG":"But this too must be the result of my foolish actions. I will not make excuses. So...","TWN":"這也是我無法逃避的命運結果。我不會找藉口。所以……"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"오너라.","JPN":"来い。","ENG":"Come.","TWN":"來吧。"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"하, 제가 어리석었군요.","JPN":"は、私が愚かだった。","ENG":"Ha! It seems I was the foolish one.","TWN":"哈，我真是愚蠢啊。"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_COMBAT_ALL_EARTHQUAKE_02"},{"id":"L12_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"침식체 따위에게 아무래도 너무나 많은 걸 바란 모양이에요.","JPN":"侵食体なんかに期待しすぎたみたいです。","ENG":"I expected too much from a C.O.","TWN":"看來對侵蝕體這種東西期望太高了。"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그때도…… 그리고 지금도.","JPN":"あの時も……そして今も。","ENG":"Even then... and even now.","TWN":"那時候也是……現在也是。"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"당장이라도 당신의 그 목을 베고, 핵을 짓밟아 부셔버리고 싶지만…….","JPN":"今すぐあなたの首を斬り落とし、核を踏みつけて壊してやりたいところですが……","ENG":"I wish to cut off your head and crush that core of yours, but...","TWN":"我真想立刻砍下你的頭，踩碎你的核心……"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L17_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그럼에도 당신은 이 각본에서 가장 중요한 배역을 맡고 있어요.","JPN":"でも、あなたはこの脚本で一番重要な配役を担当している。","ENG":"you play the most important role in my script.","TWN":"儘管如此，你在這個劇本中扮演著最重要的角色。"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그러니, 오늘은 어디까지나 본 무대를 위한 리허설.","JPN":"今日はあくまで、本番のためのリハーサルです。","ENG":"So, today is merely a rehearsal for the main show.","TWN":"所以，今天只是為了正式演出做的彩排。"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"존재해선 안 될 악취……?","JPN":"存在してはいけない悪臭……？","ENG":"The stench that should not exist...?","TWN":"不應該存在的惡臭……？"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"설마, 네놈……!","JPN":"まさか、貴様……！","ENG":"It cannot be... Did you...?!","TWN":"這不應該……！是你……！"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SWAN_SIX_NULL_ON","text":{"KOREA":"자아, 그럼 시작하죠.","JPN":"さあ、始めましょう。","ENG":"Now, let us begin.","TWN":"那麼，開始吧！"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_ON","face":"UNIT_PRIDE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SWAN_SIX_NULL_ON","text":{"KOREA":"부디, 이번에는 그때처럼 늦지 않기를…….","JPN":"どうか、今回はあの時のように遅れないでください。","ENG":"I hope you will not be late like last time...","TWN":"拜託，這次不要像那時候一樣遲到……"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_ON","face":"UNIT_LAUGH"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SWAN_SIX_NULL_ON","text":{"KOREA":"우행의 기사여.","JPN":"愚行の騎士よ。","ENG":"The foolish knight.","TWN":"愚行的騎士啊。"},"stage":{"bg":"COUNTRYROAD","bgm":"BATTLE_BOSS_EPIC_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_ON","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};